import React,{useEffect,useState}from"react";import{Building2,Mail,Phone,ShieldCheck}from"lucide-react";import{authAPI}from"../../services/api.js";import{useToast}from"../../components/ui/Toast.jsx";import{CardPanel,DetailsGrid,PageHeader,StatusPill}from"../../components/ui/PortalUI.jsx";
export default function VendorCompanyProfilePage(){const{showToast}=useToast();const[profile,setProfile]=useState(null);useEffect(()=>{(async()=>{try{setProfile(await authAPI.profile("vendor"))}catch(e){showToast(e.message,"error")}})()},[]);return <div className="page-wrap"><PageHeader icon={Building2} title="Company Profile" subtitle="Manage your company information and verification status."/><CardPanel title="Company Details" action={<button className="red-btn">Edit Profile</button>}><div className="profile-detail-card"><div className="vendor-avatar">{(profile?.company_name||"V").slice(0,1)}</div><div><h2>{profile?.company_name||"Vendor Company"}</h2><p>{profile?.contact_person||"Contact person"}</p><div className="filter-tabs" style={{marginTop:10}}><button className="active"><ShieldCheck size={12}/> {profile?.verification_status||"pending"}</button><button className="active">{profile?.status||"active"}</button></div></div></div><DetailsGrid rows={[["Company Name",profile?.company_name],["Contact Person",profile?.contact_person],["Email",<><Mail size={14}/>{profile?.email}</>],["Mobile",<><Phone size={14}/>{profile?.mobile}</>],["Address",profile?.address],["Postcode",profile?.postcode],["Company Registration",profile?.company_registration_number],["VAT Number",profile?.vat_number],["Insurance",profile?.insurance_details],["Years in Business",profile?.years_experience],["Rating",`${profile?.rating||"0.0"} / 5`],["Verification",<StatusPill value={profile?.verification_status}/>]]}/></CardPanel></div>}
